import{_ as o,o as t,c as r,ak as l,aG as a}from"./chunks/framework.DwgkYvd1.js";const O=JSON.parse('{"title":"S32DS 集成 FreeROTS 配置日志","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOSAR 实践/S32DS集成FreeRTOS配置日志.md","filePath":"AUTOSAR 实践/S32DS集成FreeRTOS配置日志.md"}'),s={name:"AUTOSAR 实践/S32DS集成FreeRTOS配置日志.md"};function S(c,e,i,p,d,_){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="s32ds-集成-freerots-配置日志" tabindex="-1">S32DS 集成 FreeROTS 配置日志 <a class="header-anchor" href="#s32ds-集成-freerots-配置日志" aria-label="Permalink to “S32DS 集成 FreeROTS 配置日志”">​</a></h1><p>S32DS 基础项目来自于一个配好的在 NXP S32K144 EVB V2.0 开发板上点亮 LED PD0 的示例工程，采用符合 AUTOSAR 4.4.0 标准的 S32DS + EB Tresos Studio 配置流程。</p><p>FreeRTOS 集成是来自一个已经配置好的拥有完整目录结构的项目，从其中裁剪 Rte 和 Os 部分到上述示例工程中。项目如下。</p><p>RES_Project.zip</p><blockquote><p>该项目的 MCAL 部分配置如 <a href="./EB Tresos Mcal 最小系统搭建.html">EB Tresos Mcal 最小系统搭建</a>。</p></blockquote><p>解压，将其中 02_Rte 和 03_Bsw/Os 部分粘贴入现有的项目根目录下，即形成如下目录结构：</p><p><img src="'+a+'" alt=""></p><p>打开 Project Settings（右键项目 -&gt; Properties）-&gt; C/C++ Build -&gt; Settings，完成如下操作：</p><ol><li>将宏定义 <code>NUMBER_OF_CORES</code> 添加到 Standard S32DS C Compiler -&gt; Preprocessor -&gt; Defined Symbols 中；</li><li>将如下路径添加到 Standard S32DS C Compiler -&gt; Includes -&gt;Include Paths (-l) 中： <ol><li><code>&quot;${workspace_loc:/${ProjName}/Os/include}&quot;</code></li><li><code>&quot;${workspace_loc:/${ProjName}/Os/portable/GCC/ARM_CM4F}&quot;</code></li><li><code>&quot;${workspace_loc:/${ProjName}/Os/portable/MemMang}&quot;</code></li><li><code>&quot;${workspace_loc:/${ProjName}/Os/config}&quot;</code></li><li><code>&quot;${workspace_loc:/${ProjName}/Rte}&quot;</code></li></ol></li><li>添加后点击 Apply and Close。</li></ol><p>之后，在左侧 Project Explorer 中完成如下操作：</p><ol><li>右键 Os 文件夹 -&gt; Build Path -&gt; Add to -&gt; Debug_FLASH，保证 Os 文件夹中每个子文件夹都是<strong>黑体而非灰色字体</strong>；</li><li>对 Rte 文件夹完成相同操作；</li><li>对 Rte 文件夹中的 include 和 src 文件夹右键 -&gt; Build Path -&gt; Remove from -&gt; Debug_FLASH，让其变成<strong>灰色字体</strong>。</li></ol><p>之后点击 Build，即可编译成功。</p><blockquote><p>对于 FreeRTOS 的具体解释，如 <a href="./../FreeRTOS 学习笔记/FreeRTOS 源码架构.html">FreeRTOS 源码架构</a> 对于 FreeRTOS 的通用移植，如 <a href="./../FreeRTOS 学习笔记/FreeRTOS 移植.html">FreeRTOS 移植</a> 对于 FreeRTOS 的源码解释，如 <a href="./../FreeRTOS 学习笔记/FreeRTOS 自实现/源码分析/总览.html">总览</a></p></blockquote>',13)])])}const R=o(s,[["render",S]]);export{O as __pageData,R as default};
